import React, { useEffect, useState } from 'react';
import CadastroSCM from '../components/CadastroSCM';
import MenuLateral from '../components/MenuLateral';
import { useLocation } from 'react-router-dom';

const statusCores = {
  NOVO: '#1976d2',
  ATIVO: '#388e3c',
  CORRIGIR: '#fbc02d',
  SUSPENSO: '#d32f2f'
};
const statusNomes = {
  NOVO: 'Novo',
  ATIVO: 'Ativo',
  CORRIGIR: 'Corrigir',
  SUSPENSO: 'Suspenso'
};

const PaginaCadastroSCM = () => {
  const [cliente, setCliente] = useState(null);
  const location = useLocation();

  useEffect(() => {
    // Tenta obter o cliente do localStorage ou query param (exemplo: /scm/cadastro?id=123)
    const params = new URLSearchParams(location.search);
    const id = params.get('id');
    if (id) {
      fetch(`http://localhost:5000/api/clientes/${id}`)
        .then(async resp => {
          if (!resp.ok) return;
          const data = await resp.json();
          setCliente(data);
        });
    }
  }, [location.search]);

  return (
    <div style={{display:'flex'}}>
      <MenuLateral />
      <div style={{marginLeft:200, flex:1}}>
        {cliente ? (
          <>
            <div style={{background:'#1976d2',borderRadius:'0 0 20px 20px',padding:'2rem',color:'#fff',marginTop:'1rem',position:'relative',boxShadow:'0 2px 8px #0001',maxWidth:1100,marginLeft:'auto',marginRight:'auto'}}>
              <h2 style={{margin:0,fontWeight:700}}>{cliente.razaoSocial}</h2>
              <div style={{display:'flex',alignItems:'center',gap:'1rem',marginTop:'0.5rem'}}>
                <span style={{fontWeight:700,fontSize:'1.1rem'}}>CNPJ: {cliente.cnpj}</span>
                <span style={{background:statusCores[cliente.status],color:'#fff',borderRadius:'12px',padding:'0.2rem 1rem',fontWeight:600,fontSize:'0.95rem'}}>{statusNomes[cliente.status]}</span>
              </div>
              <div style={{marginTop:'1rem',fontSize:'1.1rem'}}>
                <div><b>E-mail:</b> {cliente.email}</div>
                <div><b>Telefone:</b> {cliente.telefone}</div>
                <div><b>Consultoria:</b> {cliente.consultoria}</div>
              </div>
            </div>
            <CadastroSCM cnpj={cliente.cnpj} razaoSocial={cliente.razaoSocial} />
          </>
        ) : (
          <div style={{padding:40, textAlign:'center'}}>Selecione um cliente para gerar o relatório SCM.</div>
        )}
      </div>
    </div>
  );
};

export default PaginaCadastroSCM;
